PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX dqv:  <http://www.w3.org/ns/dqv#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
PREFIX afn:  <http://jena.apache.org/ARQ/function#>
SELECT ?partClass ?partClassLabel (SUM(?kgMass) AS ?totalKg) (afn:sqrt(SUM(?unc2)) AS ?unc) WHERE {
  {
    SELECT ?whole ?partClass ?partClassLabel (SUM(?v1path * ?v2path * ?itemM) AS ?kgMass) ?v1p ?v2p ?lim1 ?lim2 WHERE {
      ?whole a <https://www.purl.org/futuram#V0301030103> .
      ?whole futuram:itemMass [ qudt:numericValue ?itemM ; qudt:unit ?iu ] .
      FILTER(?iu = <http://qudt.org/vocab/unit/KiloGM>) .
      ?whole futuram:hasCompositionStatement ?st1 .
      ?st1 futuram:hasPartRelation ?pr1 .
      ?pr1 futuram:refersTo ?mid ;
           futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v1 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
      ?mid a ?partClass .
      FILTER(?partClass IN (<https://www.purl.org/futuram#elvElectricMotor>, <https://www.purl.org/futuram#elvEmbeddedElectronicsCables>, <https://www.purl.org/futuram#elvEmbeddedElectronics>, <https://www.purl.org/futuram#elvPowerElectronics>)) .
      OPTIONAL { ?partClass rdfs:label ?partClassLabel }
      ?mid futuram:hasCompositionStatement ?st2 .
      ?st2 futuram:hasPartRelation ?pr2 .
      ?pr2 futuram:refersTo ?leaf ;
           futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v2 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
      ?leaf a <https://www.purl.org/futuram#Copper> .
      ?mid futuram:itemMass [ qudt:numericValue ?itemM ; qudt:unit ?iu ] .
      ?pr1 dqv:hasQualityMeasurement [ dqv:isMeasurementOf <http://purl.org/futuram/criticality#Accuracy> ; dqv:value ?acc1 ] .
      BIND(?v1 AS ?v1path) ; BIND(?v2 AS ?v2path) ; BIND(?acc1 AS ?lim1)
    } GROUP BY ?whole ?partClass ?partClassLabel
  }
} GROUP BY ?partClass ?partClassLabel

