SELECT ?partClass ?partLabel ?totalKg ?unc WHERE {
  {
    SELECT ?partClass (SAMPLE(?pl) AS ?partLabel) (SUM(?kg) AS ?totalKg) (SUM(?unc2) AS ?sumUnc2) WHERE {
