PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX dqv: <http://www.w3.org/ns/dqv#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?compClass ?compClassLabel (SUM(?kgCu) AS ?sumKg) WHERE {
  {
    SELECT ?compClass (SUM(?v * ?mv * ?itemMass) AS ?kgCu) WHERE {
      {
        SELECT ?root ?compClass ?v ?itemMass WHERE {
          VALUES ?compInst {
            <https://www.purl.org/futuram/example#elvElectricMotor__V0301030103_2025>
            <https://www.purl.org/futuram/example#elvEmbeddedElectronicsCables__V0301030103_2025>
            <https://www.purl.org/futuram/example#elvPowerElectronics__V0301030103_2025>
            <https://www.purl.org/futuram/example#elvEmbeddedElectronicsControllers__V0301030103_2025>
            <https://www.purl.org/futuram/example#elvEmbeddedElectronicsActuators__V0301030103_2025>
            <https://www.purl.org/futuram/example#elvEmbeddedElectronicsHeadlights__V0301030103_2025>
          }
          ?compInst a ?compClass .
          ?compInst futuram:hasCompositionStatement ?stmt .
          ?stmt futuram:hasPartRelation ?pr .
          ?pr futuram:refersTo ?part ;
              futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
          <https://www.purl.org/futuram/example#V0301030103_2025> futuram:itemMass [ qudt:numericValue ?itemMass ; qudt:unit <http://qudt.org/vocab/unit/KiloGM> ] .
        }
      }
      ?part futuram:hasCompositionStatement ?stmt2 .
      ?stmt2 futuram:hasPartRelation ?pr2 .
      ?pr2 futuram:refersTo ?mid ;
           futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?mv ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
      ?mid a <https://www.purl.org/futuram#Copper> .
    } GROUP BY ?compClass
  }
  OPTIONAL { ?compClass rdfs:label ?compClassLabel }
} GROUP BY ?compClass ?compClassLabel

