PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?inst ?label ?class WHERE {
  ?inst rdfs:label ?label ; a ?class .
  FILTER(LCASE(STR(?label)) = "<instance-label>")
}
```
